var b="url",c="出库任务_新增_.html",d="generationDate",e=new Date(1781592928680.16),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="page",s="packageId",t="6e17449e683e4bdeaf510b0f4448a0cd",u="type",v="Axure:Page",w="出库任务(新增)",x="notes",y="annotations",z="fn",A="1",B="ownerId",C="db85ff86f6e04221837ad6c8ecf6209b",D="label",E="关联生产",F="说明",G="<p><span>1.下拉样式</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.以表格展示'订单号'、'工作号'、'款号'这3列</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.订单号：'生产订单号'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.工作号：取生产订单上对应的'工作号'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; iii.款号：取生产订单上对应的'款号'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.支持对各列的模糊搜索</span></p><p><span>2.每切换当前选项</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.当前下拉款仅显示对应'订单号'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.将选中订单(生产单)对应的'款号'传至“关联款号”</span></p>",H="2",I="a18dc1a5da9d402e9df5134ffbc856ec",J="关联款号：",K="<p><span>1.自动赋值</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.每切换&quot;关联生产&quot;时，将生产订单上对应的'款号'拉取过来</span></p><p><span>2.下拉样式</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.以表格展示'款号'、'款名'这2列</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.支持对各列的模糊搜索</span></p><p><span>3.每切换当前选项</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.将已选中的“关联生产”清空</span></p>",L="3",M="148f2119d3b342d2962165e9d8662c03",N="物料编码",O="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">下拉选项</span></p><p><span>1.数据源：[基础数据系统&gt;&gt;物料管理：物料明细]中 </span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">属性==</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">面料</span><span style=\"font-family:'Nunito Sans Bold Oblique', 'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;font-style:oblique;\"> </span><span>的'物料'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.下拉展示“物料编码”和“物料名称”2列</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.支持对展示字段列的模糊搜索</span></p><p><span>2.选中后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.将“物料编码”返回当前下拉域</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.同步选中物料的“物料名称”、“单位”至对应字段列</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.清空对应行已选中的“门幅(CM)”和“颜色”</span></p>",P="4",Q="ff2804d0db7740c78ef133d932d959a4",R="颜色",S="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">下拉选项</span></p><p><span>1.数据源：跟随当前行选中物料下的全部“颜色”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.展示颜色对应的“色号”、“颜色”、“颜色(中)”、“颜色(英)”、“供色单位”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.支持对展示字段列的模糊搜索</span></p><p><span>2.选中后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.仅将“颜色”返回当前下拉域</span></p>",T="5",U="ebe1530ae0fa465db4986121928bcfa3",V="门幅(CM)",W="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">下拉选项</span></p><p><span>1.数据源：跟随当前行选中物料下的全部“规格/门幅”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.展示“规格/门幅(cm)”和“克重(g/㎡)”的值</span></p><p><span>2.选中后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.将“规格/门幅(cm)”返回当前下拉域</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.同步选中对应的“克重(g/㎡)”传至当前行的“克重”</span></p>",X="6",Y="35979d6c66d44d91a0fee4e54278ed33",Z="要求出库数量",ba="<p><span>1.格式：保留2位小数</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.手动输入：无法输入第3位</span></p>",bb="7",bc="1c67ad27fe8d48a0a5116ca55dfbdb18",bd="保存",be="<p><span>1.校验'要求出库'的必填，否则Toast提示：请选择要求出库日期</span></p><p><span>2.校验</span><span style=\"text-decoration:underline ;\">要求出库清单</span><span>非空，否则Toast提示：出库清单为空</span></p><p><span>3.对</span><span style=\"text-decoration:underline ;\">要求出库清单</span><span>内各列进行校验</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a.校验&quot;物料编码&quot;、&quot;颜色&quot;、&quot;门幅(CM)&quot;非空，否则Toast提示：请选择SKU</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b.校验单行&quot;物料编码+颜色+门幅(CM)&quot;对应存在SKU，否则Toast提示：非系统内SKU(第</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">X</span><span>行)</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; d.校验清单内无重复SKU，否则Toast提示：SKU重复(第</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">X</span><span>行，第</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#0000FF;\">Y</span><span>行)</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; e.校验&quot;要求出库数量&quot;均大于0，否则Toast提示：要求出库数量须大于0</span></p><p><span>4.通过全部校验</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; a.创建面料出库任务至[面料仓库系统&gt;&gt;面料仓库：出库任务]</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a1.出库任务单号：MLCK+4位年月+3位流水</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a2.状态：进行中</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a3.类型：直接申请</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a4.生产订单、工作号、关联款号、用料单位、要求出库、出库备注：跟随当前基本信息的&quot;关联生产&quot;、&quot;关联生产&quot;对应的'工作号'、&quot;关联款号&quot;、&quot;用料单位&quot;、&quot;要求出库&quot;、&quot;备注&quot;</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a5.要求出库清单：同当前</span><span style=\"text-decoration:underline ;\">要求出库清单</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a6.创建人、创建时间：以当前操作账号、操作时间为准</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; a7.附：无须区分仓库、属主</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; b.页面跳转：跳转至[面料仓库系统&gt;&gt;面料仓库：出库任务]列表页</span></p>",bf="style",bg="baseStyle",bh="627587b6038d43cca051c114ac41ad32",bi="pageAlignment",bj="center"